  target: BookerTarget;
  monthsToFetch?: number;
  eventTypeId?: number;
  fetchMeta?: boolean;
};

type ResolvedEventType = {
  eventTypeId: number | null;
  eventTypeSlug: string | null;
};

type FetchRawBookerResult =
  | {
      ok: true;
      raw: {
        me: unknown;
        eventTypes: unknown;
        selectedEventType: unknown | null;
        slots: unknown;
      };
      resolved: ResolvedEventType;
    }
  | {
      ok: false;
      error: string;
    };

function buildMePayload(target: BookerTarget, eventType: EventType): unknown {
  const owner = eventType.users?.[0] ?? eventType.hosts?.[0];
  const fallbackName =
    target.type === "user"
      ? target.username
      : (owner?.username ?? "Unknown user");

  return {
    data: {
      avatarUrl: owner?.avatarUrl,
      name: owner?.name ?? fallbackName,
      username: owner?.username ?? fallbackName,
    },
  };
}

function buildSlotRange(monthIso: string, monthsToFetch: number) {
  const monthDate = new Date(monthIso);
  const safeMonthDate = Number.isNaN(monthDate.getTime())
    ? new Date()
    : monthDate;
  const monthStart = new Date(
    Date.UTC(safeMonthDate.getFullYear(), safeMonthDate.getMonth(), 1),
  );
  const rangeEnd = new Date(
    Date.UTC(
      safeMonthDate.getFullYear(),
      safeMonthDate.getMonth() + monthsToFetch,
      0,
    ),
  );
  const now = new Date();
  const todayUtc = new Date(
    Date.UTC(now.getFullYear(), now.getMonth(), now.getDate()),
  );
  const rangeStart = monthStart < todayUtc ? todayUtc : monthStart;

  return {
    end: rangeEnd.toISOString().slice(0, 10),
    start: rangeStart.toISOString().slice(0, 10),
  };
}

async function fetchSlotsForEventType(
  input: FetchRawBookerInput,
  resolved: ResolvedEventType,
): Promise<unknown> {
  const monthsToFetch = Math.max(1, Math.floor(input.monthsToFetch ?? 1));
  const { end, start } = buildSlotRange(input.monthIso, monthsToFetch);

  if (resolved.eventTypeId != null) {
    return getAvailableSlots({
      end,
      eventTypeId: resolved.eventTypeId,
      start,
      timeZone: input.timeZone,
    });
  }

  const eventTypeSlug = resolved.eventTypeSlug;
  if (!eventTypeSlug) {
    throw new CalApiError(
      "Missing event type slug for slot lookup.",
      "MISSING_SLUG",
      400,
    );
  }

  return getAvailableSlots({
    end,
    eventTypeSlug,
    start,
    timeZone: input.timeZone,
    username: input.target.type === "user" ? input.target.username : undefined,
  });
}

async function resolveEventType(
  target: BookerTarget,
): Promise<EventType | null> {
  if (target.type === "user") {
    return getEventType({
      eventSlug: target.eventSlug,
      orgId: target.orgId,
      username: target.username,
    });
  }

  if (target.type === "team") {
    return getTeamEventType({
      eventSlug: target.eventSlug,
      orgId: target.orgId,
      teamId: target.teamId,
    });
  }

  const parsed = parseBookingUrlTarget(target.bookingUrl);
  if (parsed.type === "user") {
    return getEventType({
      eventSlug: parsed.eventSlug,
      orgId: parsed.orgId,
      username: parsed.username,
    });
  }

  return getTeamSlugEventType({
    eventSlug: parsed.eventSlug,
    orgId: parsed.orgId,
    teamSlug: parsed.teamSlug,
  });
}

export async function fetchRawBookerDataAction(
  input: FetchRawBookerInput,
): Promise<FetchRawBookerResult> {
  try {
    if (input.eventTypeId != null) {
      const resolved: ResolvedEventType = {
        eventTypeId: input.eventTypeId,
        eventTypeSlug: null,
      };
      const slots = await fetchSlotsForEventType(input, resolved);

      if (!input.fetchMeta) {
        return {
          ok: true,
          raw: { eventTypes: null, me: null, selectedEventType: null, slots },
          resolved,
        };
      }

      const selectedEventType = await getEventTypeById(input.eventTypeId);

      return {
        ok: true,
        raw: {
          eventTypes: [selectedEventType],
          me: buildMePayload(input.target, selectedEventType),
          selectedEventType,
          slots,
        },
        resolved,
      };
    }

    const selectedEventType = await resolveEventType(input.target);

    if (!selectedEventType) {
      return {
        error: "No event type found for the provided target.",
        ok: false,
      };
    }

    const resolved: ResolvedEventType = {
      eventTypeId: selectedEventType.id,
      eventTypeSlug: selectedEventType.slug,
    };
    const slots = await fetchSlotsForEventType(input, resolved);

    return {
      ok: true,
      raw: {
        eventTypes: [selectedEventType],
        me: buildMePayload(input.target, selectedEventType),
        selectedEventType,
        slots,
      },
      resolved,
    };
  } catch (error) {
    return {
      error:
        error instanceof CalApiError
          ? error.message
          : error instanceof Error
            ? error.message
            : "Could not load booker data.",
      ok: false,
    };
  }
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { fetchRawBookerDataAction } from "@/lib/booker/actions";
import type { BookerTarget } from "@/lib/booker/target";
import {
  type BookerMeta,
  extractBookingWindowEnd,
  extractEventTypeInfo,
  extractHost,
  extractMinimumBookingNotice,
  extractSlotsByDate,
  filterBookableSlots,
  findFirstAvailableDate,
  findNextAvailableDate,
  prefers24Hour,
  toDateKey,
} from "@/lib/booker/utils";

const WINDOW_MONTHS = 3;

// Stored in error state for non-Error failures so the (overridable) generic
// message can be resolved at render time without coupling the effect to labels.
export const GENERIC_LOAD_ERROR = "\u0000booker-generic-load-error";

type UseBookerParams = {
  target: BookerTarget;
  timezone?: string;
};

export type UseBookerResult = {
  meta: BookerMeta | null;
  error: string | null;
  isPending: boolean;
  locale: string;
  selectedTimeZone: string;
  setSelectedTimeZone: (timeZone: string) => void;
  currentMonth: Date;
  startMonth: Date;
  todayStart: Date;
  selectedDate: Date | undefined;
  selectedInCurrentMonth: boolean;
  daySlots: string[];
  nextAvailableDate: Date | null;
  is24Hour: boolean;
  setIs24Hour: (value: boolean) => void;
  selectedTime: string | null;
  setSelectedTime: (time: string | null) => void;
  handleMonthChange: (month: Date) => void;
  handleSelectDate: (nextDate: Date | undefined) => void;
  isDayDisabled: (date: Date) => boolean;
  goToDate: (date: Date) => void;
};

// All booker data + interaction logic: fetching/windowing cal.com availability,
// derived selection state, and the handlers the UI wires to the calendar.
export function useBooker({
  target,
  timezone,
}: UseBookerParams): UseBookerResult {
  const [meta, setMeta] = useState<BookerMeta | null>(null);
  const [slotsByDate, setSlotsByDate] = useState<Record<string, string[]>>({});
  const [error, setError] = useState<string | null>(null);
  const [isPending, setIsPending] = useState(false);
  const [timeZone] = useState(
    () => Intl.DateTimeFormat().resolvedOptions().timeZone || "UTC",
  );
  const [locale] = useState(
    () => Intl.DateTimeFormat().resolvedOptions().locale || "en-US",
  );
  const [currentMonth, setCurrentMonth] = useState(() => new Date());
  const [selectedTimeZone, setSelectedTimeZone] = useState(
    timezone ?? timeZone,
  );
  const [selectedDate, setSelectedDate] = useState<Date | undefined>(undefined);
  const [selectedTime, setSelectedTime] = useState<string | null>(null);
  const [is24Hour, setIs24Hour] = useState(() => prefers24Hour(locale));
  const coveredMonthsRef = useRef<Set<string>>(new Set());
  const resolvedRef = useRef<{
    eventTypeId: number | null;
    eventTypeSlug: string | null;
  }>({ eventTypeId: null, eventTypeSlug: null });
  const lastIdentityRef = useRef<string | null>(null);
  const lastTimeZoneRef = useRef<string | null>(null);
  const autoSelectedMonthRef = useRef<string | null>(null);
  const slotsByDateRef = useRef<Record<string, string[]>>({});
  const minimumBookingNoticeRef = useRef(0);
  const inFlightMonthsRef = useRef<Map<string, Promise<void>>>(new Map());
  const availabilityRequestVersionRef = useRef(0);

  const targetIdentity = useCallback((): string => {
    if (target.type === "user") {
      return `user:${target.username}:${target.eventSlug}:${target.orgId ?? ""}`;
    }
    if (target.type === "team") {
      return `team:${target.teamId}:${target.eventSlug}:${target.orgId ?? ""}`;
    }
    return `link:${target.bookingUrl}`;
  }, [target]);

  const buildKey = useCallback(
    (month: Date) =>
      `${targetIdentity()}|${selectedTimeZone}|${month.getFullYear()}-${month.getMonth()}`,
    [selectedTimeZone, targetIdentity],
  );

  // Fetch a window of several months in a single request, anchored at `anchor`.
  const fetchWindow = useCallback(
    async (anchor: Date): Promise<void> => {
      const anchorKey = buildKey(anchor);

      if (coveredMonthsRef.current.has(anchorKey)) {
        return;
      }

      const existingRequest = inFlightMonthsRef.current.get(anchorKey);
      if (existingRequest) {
        await existingRequest;
        return;
      }

      const requestVersion = availabilityRequestVersionRef.current;
      const windowMonthKeys = Array.from(
        { length: WINDOW_MONTHS },
        (_, offset) =>
          buildKey(
            new Date(anchor.getFullYear(), anchor.getMonth() + offset, 1),
          ),
      );
      const request = (async () => {
        const result = await fetchRawBookerDataAction({
          fetchMeta: resolvedRef.current.eventTypeId == null,
          monthIso: anchor.toISOString(),
          monthsToFetch: WINDOW_MONTHS,
          target,
          timeZone: selectedTimeZone,
          eventTypeId: resolvedRef.current.eventTypeId ?? undefined,
        });

        if (!result.ok) {
          throw new Error(result.error);
        }

        if (availabilityRequestVersionRef.current !== requestVersion) {
          return;
        }

        resolvedRef.current = result.resolved;

        for (let offset = 0; offset < WINDOW_MONTHS; offset += 1) {
          const month = new Date(
            anchor.getFullYear(),
            anchor.getMonth() + offset,
            1,
          );
          coveredMonthsRef.current.add(buildKey(month));
        }

        // The host/event metadata only comes back on the full (non slots-only)
        // fetch, so set it once when present.
        if (result.raw.me) {
          const host = extractHost(result.raw.me);
          const eventType = extractEventTypeInfo(result.raw.selectedEventType);
          minimumBookingNoticeRef.current = extractMinimumBookingNotice(
            result.raw.selectedEventType,
          );
          setMeta(
            (prev) =>
              prev ?? {
                hostName:
                  host.hostName === "Unknown user" && target.type === "user"
                    ? target.username
                    : host.hostName,
                hostAvatarUrl: host.hostAvatarUrl,
                eventTypeTitle: eventType.eventTypeTitle,
                eventTypeDescription: eventType.eventTypeDescription,
                eventTypeDurationMinutes: eventType.eventTypeDurationMinutes,
                eventTypeLocation: eventType.eventTypeLocation,
                eventTypeLocationProvider: eventType.eventTypeLocationProvider,
                eventTypeImageUrl: eventType.eventTypeImageUrl,
                bookingWindowEnd: extractBookingWindowEnd(
                  result.raw.selectedEventType,
                ),
              },
          );
        }

        const windowSlots = filterBookableSlots(
          extractSlotsByDate(result.raw.slots, selectedTimeZone),
          selectedTimeZone,
          minimumBookingNoticeRef.current,
          new Date(),
        );
        const mergedSlots = { ...slotsByDateRef.current, ...windowSlots };
        slotsByDateRef.current = mergedSlots;
        setSlotsByDate(mergedSlots);
      })();

      for (const monthKey of windowMonthKeys) {
        inFlightMonthsRef.current.set(monthKey, request);
      }

      try {
        await request;
      } finally {
        for (const monthKey of windowMonthKeys) {
          if (inFlightMonthsRef.current.get(monthKey) === request) {
            inFlightMonthsRef.current.delete(monthKey);
          }
        }
      }
    },
    [buildKey, selectedTimeZone, target],
  );

  useEffect(() => {
    let cancelled = false;

    const load = async () => {
      const identity = targetIdentity();

      // A different user/event means a different event type and metadata, so
      // reset everything and force a full fetch.
      if (
        lastIdentityRef.current !== null &&
        lastIdentityRef.current !== identity
      ) {
        coveredMonthsRef.current = new Set();
        inFlightMonthsRef.current.clear();
        availabilityRequestVersionRef.current += 1;
        resolvedRef.current = { eventTypeId: null, eventTypeSlug: null };
        slotsByDateRef.current = {};
        autoSelectedMonthRef.current = null;
        setMeta(null);
        setSlotsByDate({});
      } else if (
        lastTimeZoneRef.current !== null &&
        lastTimeZoneRef.current !== selectedTimeZone
      ) {
        // Timezone only affects slot times, not the resolved event type, so
        // just invalidate coverage and refetch (slots-only) with the new zone.
        coveredMonthsRef.current = new Set();
        inFlightMonthsRef.current.clear();
        availabilityRequestVersionRef.current += 1;
      }
      lastIdentityRef.current = identity;
      lastTimeZoneRef.current = selectedTimeZone;

      if (!coveredMonthsRef.current.has(buildKey(currentMonth))) {
        setIsPending(true);
        try {
          await fetchWindow(currentMonth);
          if (cancelled) {
            return;
          }
          setError(null);
        } catch (caught) {
          if (cancelled) {
            return;
          }
          setError(
            caught instanceof Error ? caught.message : GENERIC_LOAD_ERROR,
          );
        } finally {
          if (!cancelled) {
            setIsPending(false);
          }
        }
      } else {
        setError(null);
        setIsPending(false);
      }

      // Auto-select the first available day the first time this month's
      // availability is known (on load and on month navigation).
      const monthKey = `${currentMonth.getFullYear()}-${currentMonth.getMonth()}`;
      if (!cancelled && autoSelectedMonthRef.current !== monthKey) {
        const todayStart = new Date();
        todayStart.setHours(0, 0, 0, 0);
        const firstAvailable = findFirstAvailableDate(
          currentMonth,
          slotsByDateRef.current,
          selectedTimeZone,
          todayStart,
        );
        if (firstAvailable) {
          autoSelectedMonthRef.current = monthKey;
          setSelectedDate(firstAvailable);
          setSelectedTime(null);
        }
      }

      // Warm the next uncovered window boundary, not just the adjacent month.
      // This keeps navigation instant when the user reaches the end of the
      // currently-covered 3-month range.
      const nextWindow = new Date(
        currentMonth.getFullYear(),
        currentMonth.getMonth() + WINDOW_MONTHS,
        1,
      );
      if (!coveredMonthsRef.current.has(buildKey(nextWindow))) {
        void fetchWindow(nextWindow).catch(() => {});
      }
    };

    void load();

    return () => {
      cancelled = true;
    };
  }, [buildKey, currentMonth, fetchWindow, selectedTimeZone, targetIdentity]);

  useEffect(() => {
    if (!timezone) {
      return;
    }
    setSelectedTimeZone(timezone);
  }, [timezone]);

  const todayStart = new Date();
  todayStart.setHours(0, 0, 0, 0);
  const startMonth = new Date(
    todayStart.getFullYear(),
    todayStart.getMonth(),
    1,
  );

  // Only treat the selection as "live" when it belongs to the month currently
  // on screen. Navigating to a month without availability leaves selectedDate
  // pointing at a previous month's day, which would otherwise keep its slots
  // visible instead of the empty state.
  const selectedInCurrentMonth =
    selectedDate != null &&
    selectedDate.getMonth() === currentMonth.getMonth() &&
    selectedDate.getFullYear() === currentMonth.getFullYear();
  const selectedDateKey = toDateKey(
    selectedDate ?? new Date(),
    selectedTimeZone,
  );
  const daySlots = selectedInCurrentMonth
    ? (slotsByDate[selectedDateKey] ?? [])
    : [];
  const nextAvailableDate = findNextAvailableDate(
    slotsByDate,
    selectedTimeZone,
    todayStart,
  );

  const handleMonthChange = (month: Date) => {
    setCurrentMonth(month);
    // Flip to pending in the same render as the month change when the target
    // month still needs fetching, so the skeleton shows immediately instead of
    // the empty state flashing for a frame before the async effect runs.
    if (!coveredMonthsRef.current.has(buildKey(month))) {
      setIsPending(true);
    }
    // For an already-loaded month, select the first available day in the same
    // update as the month change so the selection doesn't flicker.
    const monthTodayStart = new Date();
    monthTodayStart.setHours(0, 0, 0, 0);
    const firstAvailable = findFirstAvailableDate(
      month,
      slotsByDateRef.current,
      selectedTimeZone,
      monthTodayStart,
    );
    if (firstAvailable) {
      autoSelectedMonthRef.current = `${month.getFullYear()}-${month.getMonth()}`;
      setSelectedDate(firstAvailable);
      setSelectedTime(null);
    }
  };

  const handleSelectDate = (nextDate: Date | undefined) => {
    if (!nextDate) {
      return;
    }
    setSelectedDate(nextDate);
    setSelectedTime(null);
    autoSelectedMonthRef.current = `${nextDate.getFullYear()}-${nextDate.getMonth()}`;
    const isDifferentMonth =
      nextDate.getMonth() !== currentMonth.getMonth() ||
      nextDate.getFullYear() !== currentMonth.getFullYear();
    if (isDifferentMonth) {
      setCurrentMonth(nextDate);
    }
  };

  const isDayDisabled = (date: Date) => {
    const dayStart = new Date(date);
    dayStart.setHours(0, 0, 0, 0);
    if (dayStart < todayStart) {
      return true;
    }

    const dayKey = toDateKey(date, selectedTimeZone);
    return (slotsByDate[dayKey] ?? []).length === 0;
  };

  const goToDate = (date: Date) => {
    setCurrentMonth(date);
    setSelectedDate(date);
    setSelectedTime(null);
    autoSelectedMonthRef.current = `${date.getFullYear()}-${date.getMonth()}`;
  };

  return {
    meta,
    error,
    isPending,
    locale,
    selectedTimeZone,
    setSelectedTimeZone,
    currentMonth,
    startMonth,
    todayStart,
    selectedDate,
    selectedInCurrentMonth,
    daySlots,
    nextAvailableDate,
    is24Hour,
    setIs24Hour,
    selectedTime,
    setSelectedTime,
    handleMonthChange,
    handleSelectDate,
    isDayDisabled,
    goToDate,
  };
}

export type BookerMeta = {
  hostName: string;
  hostAvatarUrl: string;
  eventTypeTitle: string;
  eventTypeDescription: string;
  eventTypeDurationMinutes: number | null;
  eventTypeLocation: string;
  eventTypeLocationProvider: string;
  eventTypeImageUrl: string;
  bookingWindowEnd: Date | null;
};

export type EventTypeInfo = {
  eventTypeTitle: string;
  eventTypeDescription: string;
  eventTypeDurationMinutes: number | null;
  eventTypeLocation: string;
  eventTypeLocationProvider: string;
  eventTypeImageUrl: string;
};

export function prettifyLocation(value: string): string {
  const normalized = value.trim().toLowerCase();

  const known: Record<string, string> = {
    "integrations:google:meet": "Google Meet",
    "integrations:zoom": "Zoom",
    "integrations:microsoft:teams": "Microsoft Teams",
    "integrations:whereby": "Whereby",
    "integrations:jitsi": "Jitsi Meet",
    inperson: "In person",
    phone: "Phone call",
  };

  if (known[normalized]) {
    return known[normalized];
  }

  if (normalized.startsWith("integrations:")) {
    const parts = normalized.replace("integrations:", "").split(":");
    return parts
      .filter(Boolean)
      .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
      .join(" ");
  }

  return value
    .replace(/[_:-]+/g, " ")
    .split(" ")
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function normalizeAvatarUrl(value: unknown): string {
  if (typeof value !== "string") {
    return "";
  }

  const trimmed = value.trim();
  if (!trimmed) {
    return "";
  }

  if (trimmed.startsWith("http://") || trimmed.startsWith("https://")) {
    return trimmed;
  }

  if (trimmed.startsWith("//")) {
    return `https:${trimmed}`;
  }

  if (trimmed.startsWith("/")) {
    return `https://app.cal.com${trimmed}`;
  }

  return trimmed;
}

export function extractHost(payload: unknown): {
  hostName: string;
  hostAvatarUrl: string;
} {
  if (!payload || typeof payload !== "object") {
    return { hostName: "Unknown user", hostAvatarUrl: "" };
  }

  const root = payload as Record<string, unknown>;
  const data = (root.data as Record<string, unknown> | undefined) ?? root;
  const profile =
    data.profile && typeof data.profile === "object"
      ? (data.profile as Record<string, unknown>)
      : undefined;

  const rawAvatar =
    data.avatarUrl ??
    data.avatar_url ??
    data.avatar ??
    profile?.avatarUrl ??
    profile?.avatar_url ??
    profile?.avatar;

  return {
    hostName: String(
      data.name ?? data.username ?? data.email ?? "Unknown user",
    ),
    hostAvatarUrl: normalizeAvatarUrl(rawAvatar),
  };
}

export function extractEventTypeInfo(payload: unknown): EventTypeInfo {
  if (!payload || typeof payload !== "object") {
    return {
      eventTypeTitle: "No event type found",
      eventTypeDescription: "",
      eventTypeDurationMinutes: null,
      eventTypeLocation: "Unknown",
      eventTypeLocationProvider: "",
      eventTypeImageUrl: "",
    };
  }

  const record = payload as Record<string, unknown>;
  const durationValue =
    record.lengthInMinutes ??
    record.duration ??
    record.length ??
    record.minutes;
  const duration =
    typeof durationValue === "number"
      ? durationValue
      : typeof durationValue === "string" &&
          Number.isFinite(Number(durationValue))
        ? Number(durationValue)
        : null;

  const locationsRaw = record.locations;
  let locationText = "Unknown";
  let locationProvider = "";

  if (Array.isArray(locationsRaw) && locationsRaw.length > 0) {
    const first = locationsRaw[0];
    if (first && typeof first === "object") {
      const loc = first as Record<string, unknown>;
      const rawType =
        typeof loc.type === "string"
          ? loc.type
          : typeof loc.value === "string" &&
              loc.value.startsWith("integrations:")
            ? loc.value
            : "";
      locationProvider = rawType;
      locationText = String(
        loc.type ??
          loc.label ??
          loc.value ??
          loc.address ??
          loc.location ??
          "Unknown",
      );
    } else if (typeof first === "string") {
      locationText = first;
    }
  } else if (typeof record.location === "string") {
    locationText = record.location;
  }

  return {
    eventTypeTitle: String(
      record.title ?? record.name ?? record.slug ?? "No event type found",
    ),
    eventTypeDescription: String(record.description ?? ""),
    eventTypeDurationMinutes: duration,
    eventTypeLocation: prettifyLocation(locationText),
    eventTypeLocationProvider: locationProvider,
    eventTypeImageUrl: normalizeAvatarUrl(
      record.imageUrl ??
        record.image_url ??
        record.image ??
        record.bannerUrl ??
        record.coverImage ??
        record.coverImageUrl,
    ),
  };
}

function toFiniteNumber(value: unknown): number | null {
  if (typeof value === "number" && Number.isFinite(value)) {
    return value;
  }
  if (
    typeof value === "string" &&
    value.trim() !== "" &&
    Number.isFinite(Number(value))
  ) {
    return Number(value);
  }
  return null;
}

function addCalendarDays(date: Date, days: number): Date {
  return new Date(date.getFullYear(), date.getMonth(), date.getDate() + days);
}

function addBusinessDays(date: Date, days: number): Date {
  const result = new Date(date.getFullYear(), date.getMonth(), date.getDate());
  let remaining = Math.max(0, days);
  while (remaining > 0) {
    result.setDate(result.getDate() + 1);
    const dayOfWeek = result.getDay();
    if (dayOfWeek !== 0 && dayOfWeek !== 6) {
      remaining -= 1;
    }
  }
  return result;
}

function parseDate(value: unknown): Date | null {
  if (typeof value !== "string" && typeof value !== "number") {
    return null;
  }
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

// Resolve the event type's future-booking limit (cal.com's `periodType`) into
// the last bookable date. Returns null when the event allows unlimited future
// bookings or no recognizable limit is present.
export function extractBookingWindowEnd(payload: unknown): Date | null {
  if (!payload || typeof payload !== "object") {
    return null;
  }

  const eventType = payload as Record<string, unknown>;
  const periodType =
    typeof eventType.periodType === "string"
      ? eventType.periodType.toUpperCase()
      : "";

  if (periodType === "RANGE") {
    return parseDate(eventType.periodEndDate);
  }

  if (periodType === "ROLLING" || periodType === "ROLLING_WINDOW") {
    const days = toFiniteNumber(eventType.periodDays);
    if (days != null) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      return eventType.periodCountCalendarDays
        ? addCalendarDays(today, days)
        : addBusinessDays(today, days);
    }
  }

  return null;
}

export function getInitials(name: string): string {
  const parts = name
    .split(" ")
    .map((part) => part.trim())
    .filter(Boolean)
    .slice(0, 2);

  if (parts.length === 0) {
    return "NA";
  }

  return parts.map((part) => part[0]?.toUpperCase() ?? "").join("");
}

export function formatSelectedWeekday(date: Date, locale: string): string {
  return new Intl.DateTimeFormat(locale, {
    weekday: "short",
  }).format(date);
}

export function formatSelectedDay(date: Date, locale: string): string {
  return new Intl.DateTimeFormat(locale, {
    day: "2-digit",
  }).format(date);
}

export function toDateKey(date: Date, timeZone: string): string {
  return new Intl.DateTimeFormat("en-CA", {
    day: "2-digit",
    month: "2-digit",
    timeZone,
    year: "numeric",
  }).format(date);
}

function toTimeLabel(date: Date, timeZone: string): string {
  return new Intl.DateTimeFormat("en-GB", {
    hour: "2-digit",
    hour12: false,
    minute: "2-digit",
    timeZone,
  }).format(date);
}

// Whether a locale conventionally shows time in 24-hour form, used to seed the
// 12h/24h toggle (e.g. en-US â 12h, most of Europe â 24h). Falls back to 24h.
export function prefers24Hour(locale: string): boolean {
  try {
    const resolved = new Intl.DateTimeFormat(locale, {
      hour: "numeric",
    }).resolvedOptions();
    if (typeof resolved.hour12 === "boolean") {
      return !resolved.hour12;
    }
    return resolved.hourCycle === "h23" || resolved.hourCycle === "h24";
  } catch {
    return true;
  }
}

// Slots are stored as 24h "HH:mm" strings (stable ids); reformat for display.
export function displayTimeLabel(label: string, hour12: boolean): string {
  if (!hour12) {
    return label;
  }
  const [hoursRaw, minutesRaw] = label.split(":");
  const hours = Number(hoursRaw);
  const minutes = Number(minutesRaw);
  if (Number.isNaN(hours) || Number.isNaN(minutes)) {
    return label;
  }
  const date = new Date();
  date.setHours(hours, minutes, 0, 0);
  const parts = new Intl.DateTimeFormat(undefined, {
    hour: "numeric",
    hour12: true,
    minute: "2-digit",
  }).formatToParts(date);
  return parts
    .filter((part) => part.type !== "literal" || part.value.trim() !== "")
    .map((part) =>
      part.type === "dayPeriod" ? part.value.toLowerCase() : part.value,
    )
    .join("");
}

export function isSingleDigit12HourLabel(label: string): boolean {
  const hours = Number(label.split(":")[0]);
  if (Number.isNaN(hours)) {
    return false;
  }

  const normalizedHours = hours % 12 || 12;
  return normalizedHours < 10;
}

function parseSlotDate(value: unknown): Date | null {
  if (typeof value === "string") {
    if (/^\d{2}:\d{2}$/.test(value)) {
      return null;
    }
    const parsed = new Date(value);
    return Number.isNaN(parsed.getTime()) ? null : parsed;
  }

  if (!value || typeof value !== "object") {
    return null;
  }

  const record = value as Record<string, unknown>;
  const candidate =
    record.start ??
    record.startTime ??
    record.time ??
    record.dateTime ??
    record.date;

  return parseSlotDate(candidate);
}

export function extractSlotsByDate(
  payload: unknown,
  timeZone: string,
): Record<string, string[]> {
  const byDate = new Map<string, Set<string>>();
  const addSlot = (dateKey: string, time: string) => {
    if (!byDate.has(dateKey)) {
      byDate.set(dateKey, new Set<string>());
    }
    byDate.get(dateKey)?.add(time);
  };

  if (!payload || typeof payload !== "object") {
    return {};
  }

  const visitNode = (node: unknown) => {
    if (!node || typeof node !== "object") {
      return;
    }

    if (Array.isArray(node)) {
      for (const item of node) {
        visitNode(item);
      }
      return;
    }

    const record = node as Record<string, unknown>;

    for (const [key, value] of Object.entries(record)) {
      if (/^\d{4}-\d{2}-\d{2}$/.test(key) && Array.isArray(value)) {
        for (const slot of value) {
          if (typeof slot === "string" && /^\d{2}:\d{2}$/.test(slot)) {
            addSlot(key, slot);
            continue;
          }

          const parsed = parseSlotDate(slot);
          if (!parsed) {
            continue;
          }

          addSlot(key, toTimeLabel(parsed, timeZone));
        }
      } else {
        visitNode(value);
      }
    }
  };

  visitNode(payload);

  const result: Record<string, string[]> = {};
  for (const [key, times] of byDate.entries()) {
    result[key] = Array.from(times).sort((a, b) => a.localeCompare(b));
  }

  return result;
}

// Event's minimum booking notice in minutes (cal.com `minimumBookingNotice`).
export function extractMinimumBookingNotice(payload: unknown): number {
  if (!payload || typeof payload !== "object") {
    return 0;
  }
  const minutes = toFiniteNumber(
    (payload as Record<string, unknown>).minimumBookingNotice,
  );
  return minutes != null && minutes > 0 ? minutes : 0;
}

// Drop slots that are no longer bookable: anything earlier than now plus the
// minimum booking notice, evaluated in the booking timezone. Future days are
// kept untouched; only the boundary day is partially filtered. Guards against
// showing already-passed times for today (and as the session ages).
export function filterBookableSlots(
  slotsByDate: Record<string, string[]>,
  timeZone: string,
  noticeMinutes: number,
  now: Date,
): Record<string, string[]> {
  const cutoff = new Date(now.getTime() + noticeMinutes * 60_000);
  const cutoffDateKey = toDateKey(cutoff, timeZone);
  const [cutoffHoursRaw, cutoffMinutesRaw] = toTimeLabel(
    cutoff,
    timeZone,
  ).split(":");
  const cutoffHours = Number(cutoffHoursRaw);
  const cutoffMinutes = Number(cutoffMinutesRaw);
  if (Number.isNaN(cutoffHours) || Number.isNaN(cutoffMinutes)) {
    return slotsByDate;
  }
  const cutoffOfDay = cutoffHours * 60 + cutoffMinutes;

  const result: Record<string, string[]> = {};
  for (const [dateKey, times] of Object.entries(slotsByDate)) {
    if (dateKey < cutoffDateKey) {
      continue;
    }
    if (dateKey > cutoffDateKey) {
      result[dateKey] = times;
      continue;
    }
    const kept = times.filter((time) => {
      const [hoursRaw, minutesRaw] = time.split(":");
      const hours = Number(hoursRaw);
      const minutes = Number(minutesRaw);
      if (Number.isNaN(hours) || Number.isNaN(minutes)) {
        return false;
      }
      return hours * 60 + minutes >= cutoffOfDay;
    });
    if (kept.length > 0) {
      result[dateKey] = kept;
    }
  }
  return result;
}

export function findFirstAvailableDate(
  month: Date,
  slotsByDate: Record<string, string[]>,
  timeZone: string,
  todayStart: Date,
): Date | null {
  const year = month.getFullYear();
  const monthIndex = month.getMonth();
  const daysInMonth = new Date(year, monthIndex + 1, 0).getDate();

  for (let day = 1; day <= daysInMonth; day += 1) {
    const date = new Date(year, monthIndex, day);
    const dayStart = new Date(date);
    dayStart.setHours(0, 0, 0, 0);
    if (dayStart < todayStart) {
      continue;
    }

    const key = toDateKey(date, timeZone);
    if ((slotsByDate[key] ?? []).length > 0) {
      return date;
    }
  }

  return null;
}

// Earliest loaded date (today or later) that still has open slots, used to
// offer a "jump to next availability" affordance from an empty month/day.
export function findNextAvailableDate(
  slotsByDate: Record<string, string[]>,
  timeZone: string,
  todayStart: Date,
): Date | null {
  const todayKey = toDateKey(todayStart, timeZone);
  let bestKey: string | null = null;
  for (const [key, times] of Object.entries(slotsByDate)) {
    if (times.length === 0 || key < todayKey) {
      continue;
    }
    if (bestKey === null || key < bestKey) {
      bestKey = key;
    }
  }

  if (!bestKey) {
    return null;
  }

  const [yearRaw, monthRaw, dayRaw] = bestKey.split("-");
  const year = Number(yearRaw);
  const month = Number(monthRaw);
  const day = Number(dayRaw);
  if (Number.isNaN(year) || Number.isNaN(month) || Number.isNaN(day)) {
    return null;
  }
  return new Date(year, month - 1, day);
}
